import React, { useState, useRef, useEffect } from 'react';
import chatbotService from '../../services/chatbotService';
import './ChatbotWidget.css';

const WELCOME_MESSAGE = {
  role: 'assistant',
  content: 'Bună ziua! Sunt asistentul HR Chain. Vă pot ajuta cu informații despre pontaj, concedii, salariu și programul dvs. de lucru. Cu ce vă pot ajuta?',
};

export default function ChatbotWidget() {
  const [open, setOpen] = useState(false);
  const [messages, setMessages] = useState([WELCOME_MESSAGE]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const bottomRef = useRef(null);
  const inputRef = useRef(null);

  useEffect(() => {
    if (open) {
      bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
      inputRef.current?.focus();
    }
  }, [open, messages]);

  const sendMessage = async () => {
    const text = input.trim();
    if (!text || loading) return;

    const userMsg = { role: 'user', content: text };
    const nextMessages = [...messages, userMsg];
    setMessages(nextMessages);
    setInput('');
    setLoading(true);

    try {
      const res = await chatbotService.chat(
        nextMessages.filter(m => m.role !== 'system')
      );
      const reply = res.data?.data?.reply || res.data?.reply || 'Nu am putut genera un răspuns.';
      setMessages(prev => [...prev, { role: 'assistant', content: reply }]);
    } catch {
      setMessages(prev => [
        ...prev,
        { role: 'assistant', content: 'A apărut o eroare. Vă rog încercați din nou.' },
      ]);
    } finally {
      setLoading(false);
    }
  };

  const handleKey = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const clearChat = () => setMessages([WELCOME_MESSAGE]);

  return (
    <div className={`chatbot-widget ${open ? 'open' : ''}`}>
      {/* Chat Panel */}
      {open && (
        <div className="chatbot-panel">
          <div className="chatbot-header">
            <div className="chatbot-header-info">
              <div className="chatbot-logo">⛓</div>
              <div>
                <div className="chatbot-title">Asistent Chain HR</div>
                <div className="chatbot-subtitle">Întotdeauna disponibil</div>
              </div>
            </div>
            <div className="chatbot-header-actions">
              <button className="chatbot-icon-btn" title="Șterge conversația" onClick={clearChat}>🗑</button>
              <button className="chatbot-icon-btn" title="Închide" onClick={() => setOpen(false)}>✕</button>
            </div>
          </div>

          <div className="chatbot-messages">
            {messages.map((msg, i) => (
              <div key={i} className={`chatbot-msg ${msg.role}`}>
                {msg.role === 'assistant' && <div className="chatbot-avatar">⛓</div>}
                <div className="chatbot-bubble">{msg.content}</div>
              </div>
            ))}
            {loading && (
              <div className="chatbot-msg assistant">
                <div className="chatbot-avatar">⛓</div>
                <div className="chatbot-bubble chatbot-typing">
                  <span /><span /><span />
                </div>
              </div>
            )}
            <div ref={bottomRef} />
          </div>

          <div className="chatbot-input-area">
            <textarea
              ref={inputRef}
              className="chatbot-input"
              placeholder="Scrieți un mesaj..."
              rows={1}
              value={input}
              onChange={e => setInput(e.target.value)}
              onKeyDown={handleKey}
            />
            <button
              className="chatbot-send-btn"
              onClick={sendMessage}
              disabled={!input.trim() || loading}
              aria-label="Trimite"
            >
              ➤
            </button>
          </div>
        </div>
      )}

      {/* Floating Toggle Button */}
      <button
        className="chatbot-toggle"
        onClick={() => setOpen(o => !o)}
        aria-label="Asistent HR"
      >
        {open ? '✕' : '💬'}
      </button>
    </div>
  );
}
